#include <stdio.h>
#include <stdlib.h>

int isValid(long long d, long long (*seg)[2], long long n, long long M){
    long long last = seg[0][0];
    for(long long i=1;i<n;i++){
        if(last + d > seg[i][1]) return 0;
        if(last + d < seg[i][0]) last = seg[i][0];
        else last += d;
    }
    long long first = last;
    for(long long i=n-2;i>=0;i--){
        if(first - d < seg[i][0]) return 0;
        if(first - d > seg[i][1]) first = seg[i][1];
        else first -= d;
    }
    return first + M - last >= d;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long M,N; scanf("%lld %lld",&M,&N);
        long long (*seg)[2] = malloc(N*sizeof(*seg));
        for(long long i=0;i<N;i++) scanf("%lld %lld",&seg[i][0],&seg[i][1]);
        long long lo=0, hi=M;
        while(lo<hi){
            long long mid = (lo+hi+1)/2;
            if(isValid(mid,seg,N,M)) lo=mid; else hi=mid-1;
        }
        printf("%lld\n", lo);
        free(seg);
    }
    return 0;
}

