bool feasible(long long d, const vector<array<long long,2>>& seg, long long M){
    long long last = seg[0][0];
    for(size_t i=1;i<seg.size();++i){
        if(last + d > seg[i][1]) return false;
        if(last + d < seg[i][0]) last = seg[i][0];
        else last += d;
    }
    long long first = last;
    for(int i=(int)seg.size()-2;i>=0;--i){
        if(first - d < seg[i][0]) return false;
        if(first - d > seg[i][1]) first = seg[i][1];
        else first -= d;
    }
    return first + M - last >= d;
}

