import sys

def feasible(d, seg, M):
    last = seg[0][0]
    for L, R in seg[1:]:
        if last + d > R:
            return False
        if last + d < L:
            last = L
        else:
            last += d
    first = last
    for L, R in reversed(seg[:-1]):
        if first - d < L:
            return False
        if first - d > R:
            first = R
        else:
            first -= d
    return first + M - last >= d

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        M = int(next(it)); N = int(next(it))
        seg = [(int(next(it)), int(next(it))) for __ in range(N)]
        lo, hi = 0, M
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid, seg, M):
                lo = mid
            else:
                hi = mid - 1
        out.append(str(lo))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

